{
    "level": "A2–B1",
    "intro": "In this topic you will learn the <strong>differences between each, every and all</strong> - three ways to say "each" or "everyone".",
    "rules": [
        {
            "label": "EACH",
            "color": "emerald",
            "text": "<strong>Each</strong> - each one separately (individually):",
            "example": "Each student has a book. (each his own)"
        },
        {
            "label": "EVERY",
            "color": "blue",
            "text": "<strong>Every</strong> - everyone without exception (group):",
            "example": "Every student passed. (all as a group)"
        },
        {
            "label": "ALL",
            "color": "amber",
            "text": "<strong>All</strong> - all together (generality):",
            "example": "All students are here. (all together)"
        }
    ]
}

{
    "title": "1. Main differences",
    "intro": "Main characteristics of each, every and all:",
    "rows": [
        {
            "en": "each",
            "ua": "each separately",
            "note": "+ singular noun/verb. Individually."
        },
        {
            "en": "every",
            "ua": "everyone without exception",
            "note": "+ singular noun/verb. As a group."
        },
        {
            "en": "all",
            "ua": "all together",
            "note": "+ plural noun/verb. Generality."
        }
    ],
    "warning": "📌 Each/every + singular. All + plural."
}

{
    "title": "2. EACH - each separately",
    "sections": [
        {
            "label": "Each = individually",
            "color": "emerald",
            "description": "<strong>Each</strong> means "each separately" - focus on individuality, on each element separately.",
            "examples": [
                {
                    "en": "Each student has a book.",
                    "ua": "Кожен студент має книгу (свою окрему)."
                },
                {
                    "en": "Each person is different.",
                    "ua": "Кожна людина різна (окремо)."
                },
                {
                    "en": "I gave each child a toy.",
                    "ua": "Я дав кожній дитині іграшку (окремо кожній)."
                }
            ]
        },
        {
            "label": "Each + singular",
            "color": "sky",
            "description": "<strong>Each</strong> always with a <strong>noun and a singular verb</strong>.",
            "examples": [
                {
                    "en": "Each student has... (✓)",
                    "ua": "has - singular"
                },
                {
                    "en": "Each student have... (✗)",
                    "ua": "ERROR - must has!"
                },
                {
                    "en": "Each book is interesting.",
                    "ua": "is — singular"
                }
            ],
            "note": "📌 Each always + singular (is, has, does)."
        },
        {
            "label": "Each of + plural noun",
            "color": "purple",
            "description": "You can use <strong>each of + the/these/those + plural noun</strong>. The verb is singular!",
            "examples": [
                {
                    "en": "Each of the students has a book.",
                    "ua": "Each of the students has a book."
                },
                {
                    "en": "Each of these books is good.",
                    "ua": "Each of these books is good."
                }
            ],
            "note": "Each of + plural, but verb singular!"
        }
    ]
}

{
    "title": "3. EVERY - everyone without exception",
    "sections": [
        {
            "label": "Every = as a group",
            "color": "blue",
            "description": "<strong>Every</strong> means "everyone without exception" — focus on the group as a whole, everyone without exception.",
            "examples": [
                {
                    "en": "Every student passed the exam.",
                    "ua": "Every student passed the exam (all together, without exception)."
                },
                {
                    "en": "Every day I go to work.",
                    "ua": "Every day I go to work."
                },
                {
                    "en": "Every person needs food.",
                    "ua": "Every person needs food (generally everyone)."
                }
            ]
        },
        {
            "label": "Every + singular",
            "color": "sky",
            "description": "<strong>Every</strong> is always with a <strong>noun and a singular verb</strong>.",
            "examples": [
                {
                    "en": "Every student is... (✓)",
                    "ua": "is - singular"
                },
                {
                    "en": "Every student are... (✗)",
                    "ua": "ERROR - must is!"
                },
                {
                    "en": "Every child needs love.",
                    "ua": "needs - singular"
                }
            ],
            "note": "📌 Every always + singular (is, has, does)."
        },
        {
            "label": "Every + time expressions",
            "color": "purple",
            "description": "<strong>Every</strong> is often used with time expressions.",
            "examples": [
                {
                    "en": "every day, every week, every month, every year",
                    "ua": "every day, every week, every month, every year"
                },
                {
                    "en": "I exercise every day.",
                    "ua": "I exercise every day."
                },
                {
                    "en": "We meet every Friday.",
                    "ua": " every Friday."
                }
            ],
            "note": "Every = every day, every week (regularity)."
        },
        {
            "label": "NOT possible: Every of",
            "color": "rose",
            "description": "There is NO construction <strong>every of</strong>! Use each of or all of.",
            "examples": [
                {
                    "en": "Every of the students... (✗)",
                    "ua": "ERROR - they don't say that!"
                },
                {
                    "en": "Each of the students... (✓)",
                    "ua": "Correct - each of"
                },
                {
                    "en": "All of the students... (✓)",
                    "ua": "Correct - all of"
                }
            ],
            "note": "📌 There is no "every of"! Only each of or all of."
        }
    ]
}

{
    "title": "4. ALL - all together",
    "sections": [
        {
            "label": "All = generality",
            "color": "amber",
            "description": "<strong>All</strong> means "all" or "everything" — focus on generality, on everyone together.",
            "examples": [
                {
                    "en": "All students are here.",
                    "ua": "All students are here (all together)."
                },
                {
                    "en": "All people need love.",
                    "ua": "All people need love."
                },
                {
                    "en": "I ate all the cookies.",
                    "ua": "Я з'їв усі печива."
                }
            ]
        },
        {
            "label": "All + plural",
            "color": "sky",
            "description": "<strong>All</strong> зазвичай з <strong>іменником і дієсловом у множині</strong>.",
            "examples": [
                {
                    "en": "All students are... (✓)",
                    "ua": "are - plural"
                },
                {
                    "en": "All students is... (✗)",
                    "ua": "ERROR - must be!"
                },
                {
                    "en": "All the books are interesting.",
                    "ua": "are - plural"
                }
            ],
            "note": "📌 All (plural) + plural verb (are, have, do)."
        },
        {
            "label": "All + uncountable",
            "color": "purple",
            "description": "<strong>All</strong> is also used with uncountable nouns (singular verb).",
            "examples": [
                {
                    "en": "All water is important.",
                    "ua": "All water is important."
                },
                {
                    "en": "All information is correct.",
                    "ua": "All information is correct."
                }
            ],
            "note": "All + uncountable → singular verb."
        },
        {
            "label": "All of + the/these/my",
            "color": "emerald",
            "description": "With the article, demonstrative or possessive words, we use <strong>all of</strong>.",
            "examples": [
                {
                    "en": "All of the students are all of these books are mine. the/these/those/my/your.",
                    "ua": "Усі студенти тут."
                },
                {
                    "en": "All of these books are mine.",
                    "ua": "Усі ці книги мої."
                },
                {
                    "en": "All of my friends came.",
                    "ua": "Усі мої друзі прийшли."
                }
            ],
            "note": "📌 All of + the/these/those/my/your."
        }
    ]
}

{
    "title": "5. Each vs Each - when to use what <strong>Every</strong> - when considered as a group.",
    "sections": [
        {
            "label": "Акцент: індивідуальність vs група",
            "color": "emerald",
            "description": "<strong>Each</strong> — коли важлива індивідуальність кожного. <strong>Every</strong> — коли розглядаємо як групу.",
            "examples": [
                {
                    "en": "Each student has different needs. (individual)",
                    "ua": "Each student has different needs."
                },
                {
                    "en": "Every student must pass the exam. (all as a group)",
                    "ua": "Each student has to take an exam."
                }
            ]
        },
        {
            "label": "Each - for small groups",
            "color": "blue",
            "description": "<strong>Each</strong> more often for small groups (2-10). Every is for any size. (large group)",
            "examples": [
                {
                    "en": "Each of my three cats... (мала група)",
                    "ua": "Кожен з моїх трьох котів... (each краще для 2-3 елементів)"
                },
                {
                    "en": "Every citizen has rights. (велика група)",
                    "ua": "Each citizen has rights (every for large groups)"
                }
            ],
            "note": "Each = small groups. Every = any size."
        },
        {
            "label": "Each can be after a noun",
            "color": "sky",
            "description": "<strong>Each</strong> can be after a noun. <strong>Every</strong> - only before.",
            "examples": [
                {
                    "en": "The students each have a book. (✓)",
                    "ua": "each after the noun"
                },
                {
                    "en": "The students each have a book. (✗)",
                    "ua": "every cannot after!"
                }
            ],
            "note": "📌 Each can after noun. Every - only before."
        }
    ]
}

{
    "title": "6. Every vs All - when to use",
    "sections": [
        {
            "label": "Every + singular, All + plural",
            "color": "amber",
            "description": "The main difference: <strong>every + singular</strong>, <strong>all + plural</strong>.",
            "examples": [
                {
                    "en": "Every student is... (singular)",
                    "ua": "Every student..."
                },
                {
                    "en": "All students are... (plural)",
                    "ua": "All students..."
                }
            ]
        },
        {
            "label": "All - when there is a specific group",
            "color": "blue",
            "description": "<strong>All</strong> - when we are talking about a specific, defined group.",
            "examples": [
                {
                    "en": "All the students in my class passed.",
                    "ua": "All students in my class passed (a specific group)."
                },
                {
                    "en": "Every student must study. (in general)",
                    "ua": "Every student should study (general rule)."
                }
            ],
            "note": "All = specific group. Every = general rule."
        },
        {
            "label": "All can be independent",
            "color": "sky",
            "description": "<strong>All</strong> can stand alone without a noun. <strong>Every</strong> - no.",
            "examples": [
                {
                    "en": "All are welcome. (✓)",
                    "ua": "Everyone is welcome."
                },
                {
                    "en": "Every are welcome. (✗)",
                    "ua": "ERROR — every needs a noun!"
                }
            ],
            "note": "📌 All can do it independently. Every - only + noun."
        }
    ]
}

{
    "title": "7. Position in a sentence",
    "sections": [
        {
            "label": "Each is a flexible position",
            "color": "emerald",
            "description": "<strong>Each</strong> can be: before a noun, after a noun, or at the end.",
            "examples": [
                {
                    "en": "Each student has a book.",
                    "ua": "before a noun"
                },
                {
                    "en": "The students each have a book.",
                    "ua": "after the noun"
                },
                {
                    "en": "They cost $5 each.",
                    "ua": "at the end ($5 each)"
                }
            ]
        },
        {
            "label": "Every - only before the noun",
            "color": "blue",
            "description": "<strong>Every</strong> is always <strong>only before noun</strong>.",
            "examples": [
                {
                    "en": "Every student has a book. (✓)",
                    "ua": "before a noun"
                },
                {
                    "en": "The students every have... (✗)",
                    "ua": "ERROR"
                }
            ]
        },
        {
            "label": "All — before or with of",
            "color": "amber",
            "description": "<strong>All</strong> can: before a noun (without an article) or all of + article/possessive.",
            "examples": [
                {
                    "en": "All students... (without article)",
                    "ua": "All students..."
                },
                {
                    "en": "All of the students... (with article)",
                    "ua": "All students..."
                }
            ]
        }
    ]
}

{
    "title": "8. Typical mistakes of Ukrainian speakers",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "A plural verb with each/every.",
            "wrong": "Each student are... / Every person have...",
            "right": "​​​​ <span class="font-mono">Each student is... / Every person has...</span>"
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Use of 'every of'.",
            "wrong": "Every of the students passed.",
            "right": "​​​​ <span class="font-mono">Each of the students passed. All of the students passed. 4"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Дієслово в однині з all + plural.",
            "wrong": "All students is here.",
            "right": "✅ <span class="font-mono">All students are here.</span>"
        },
        {
            "label": "Помилка 4",
            "color": "purple",
            "title": "Every after a noun.",
            "wrong": "The students every have books.",
            "right": "​​​​ <span class="font-mono">Every student has a book. / The students each have a book.</span>"
        }
    ]
}

{
    "title": "10. Practice",
    "select_title": "Exercise 1. Choose the correct word",
    "select_intro": "Fill in the blanks with each, every or all.",
    "selects": [
        {
            "label": "___ student has a book. (each / every / all)",
            "prompt": "What word?"
        },
        {
            "label": "___ students are here. (each / every / all)",
            "prompt": "What word?"
        },
        {
            "label": "I see him ___ day. (each / every / all)",
            "prompt": "What word?"
        },
        {
            "label": "___ of the books is interesting. (each / every / all)",
            "prompt": "What word?"
        },
        {
            "label": "___ of the students passed. (each / every / all)",
            "prompt": "What word?"
        }
    ],
    "options": [
        "each",
        "every",
        "all"
    ],
    "input_title": "Exercise 2. Fill in the blanks",
    "input_intro": "Write each, every or all.",
    "inputs": [
        {
            "before": "___ person is different. (each person separately)",
            "after": "→"
        },
        {
            "before": "___ people need love. (all people)",
            "after": "→"
        },
        {
            "before": "I exercise ___ morning. (every morning)",
            "after": "→"
        },
        {
            "before": "They cost $10 ___. ($10 each)",
            "after": "→"
        }
    ],
    "rephrase_title": "Exercise 3. Correct the error",
    "rephrase_intro": "Find and correct the error with each, every or all.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "Each students are here.",
            "example_target": "Each student is here."
        },
        {
            "original": "1. Every of the books is good.",
            "placeholder": "Fix the error"
        },
        {
            "original": "2. All students is ready.",
            "placeholder": "Correct the error"
        },
        {
            "original": "3. The students every have books.",
            "placeholder": "Correct the error"
        }
    ]
}

